"""Basic shape tests. These should pass even for the starter impl;
they are the agent's loop-termination signal (verify_command)."""

from __future__ import annotations

from mylib.csv_parse import parse_csv_row


def test_three_unquoted_fields() -> None:
    assert parse_csv_row("a,b,c") == ["a", "b", "c"]


def test_two_unquoted_fields() -> None:
    assert parse_csv_row("hello,world") == ["hello", "world"]


def test_trailing_newline_stripped() -> None:
    assert parse_csv_row("x,y\n") == ["x", "y"]
